package com.ichi2.anki

import android.net.Uri
import android.webkit.WebResourceRequest
import androidx.test.ext.junit.runners.AndroidJUnit4
import com.ichi2.testutils.JvmTest
import org.hamcrest.MatcherAssert.assertThat
import org.hamcrest.Matchers.notNullValue
import org.hamcrest.Matchers.nullValue
import org.junit.Before
import org.junit.Test
import org.junit.runner.RunWith
import java.io.File

@RunWith(AndroidJUnit4::class)
class ViewerResourceHandlerTest : JvmTest() {
    private lateinit var mediaDir: File
    private lateinit var handler: ViewerResourceHandler
    private val authority = "127.0.0.1:40001"

    @Before
    fun setUp() {
        super.setUp()
        mediaDir = CollectionHelper.getMediaDirectory(targetContext)
        mediaDir.mkdirs()
        handler = ViewerResourceHandler(targetContext, authority)
    }

    @Test
    fun testNormalFilename() {
        // Create a test file with a normal filename
        val testFile = File(mediaDir, "normal_image.jpg")
        testFile.createNewFile()
        testFile.writeText("test content")

        try {
            val request = createMockRequest("http://$authority/normal_image.jpg")
            val response = handler.shouldInterceptRequest(request)
            assertThat("Normal filename should be found", response, notNullValue())
        } finally {
            testFile.delete()
        }
    }

    @Test
    fun testFilenameWithHashInFragment() {
        // Create a test file with # in the filename
        val testFile = File(mediaDir, "image#test.jpg")
        testFile.createNewFile()
        testFile.writeText("test content")

        try {
            // When HTML contains <img src="image#test.jpg">, the URL parser treats
            // everything after # as a fragment, so we simulate that here
            val request = createMockRequest("http://$authority/image#test.jpg")
            val response = handler.shouldInterceptRequest(request)
            assertThat("Filename with # should be found", response, notNullValue())
        } finally {
            testFile.delete()
        }
    }

    @Test
    fun testFilenameWithEncodedHash() {
        // Create a test file with # in the filename
        val testFile = File(mediaDir, "image#test.jpg")
        testFile.createNewFile()
        testFile.writeText("test content")

        try {
            // When properly encoded in HTML as <img src="image%23test.jpg">,
            // the URL path will contain the decoded #
            val request = createMockRequest("http://$authority/image%23test.jpg")
            val response = handler.shouldInterceptRequest(request)
            assertThat("Filename with encoded # should be found", response, notNullValue())
        } finally {
            testFile.delete()
        }
    }

    @Test
    fun testNonExistentFile() {
        val request = createMockRequest("http://$authority/nonexistent.jpg")
        val response = handler.shouldInterceptRequest(request)
        assertThat("Non-existent file should return null", response, nullValue())
    }

    @Test
    fun testWrongAuthority() {
        val testFile = File(mediaDir, "test.jpg")
        testFile.createNewFile()
        testFile.writeText("test content")

        try {
            val request = createMockRequest("http://wrong.authority:1234/test.jpg")
            val response = handler.shouldInterceptRequest(request)
            assertThat("Wrong authority should return null", response, nullValue())
        } finally {
            testFile.delete()
        }
    }

    private fun createMockRequest(urlString: String): WebResourceRequest {
        return object : WebResourceRequest {
            private val uri = Uri.parse(urlString)

            override fun getUrl(): Uri = uri
            override fun isForMainFrame(): Boolean = false
            override fun isRedirect(): Boolean = false
            override fun hasGesture(): Boolean = false
            override fun getMethod(): String = "GET"
            override fun getRequestHeaders(): MutableMap<String, String> = mutableMapOf()
        }
    }
}
"}

